42	function cursedSurchargeFor(item: Item): number {
43	  return item.cursed ? basePremiumForType(item.type) * 0.5 : 0;
44	}
45	
46	function highEnchantmentSurchargeFor(item: Item): number {
47	  return (item.enchantment ?? 0) >= 5 ? basePremiumForType(item.type) * 0.3 : 0;
48	}
49	
50	function itemSurchargesFor(item: Item): number {
51	  return cursedSurchargeFor(item) + highEnchantmentSurchargeFor(item);
52	}
