54	function loyaltyDiscountFor(basePremium: number, customer: CustomerContext): number {
55	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
56	    ? basePremium * LOYALTY_DISCOUNT_RATE
57	    : 0;
58	}
