60	function premiumForGroup(type: string, count: number): number {
61	  if (COMPONENT_TYPES.includes(type) && count === BLOCK_SIZE) {
62	    return BLOCK_PREMIUM;
63	  }
64	  return count * basePremiumForType(type);
65	}
