67	export function quote(items: Item[], customer: CustomerContext): number {
68	  const counts = countByType(items);
69	
70	  const basePremium = Object.entries(counts)
71	    .reduce((sum, [type, count]) => sum + premiumForGroup(type, count), 0);
72	
73	  const itemSurcharges = items.reduce((sum, item) =>
74	    sum + itemSurchargesFor(item), 0);
75	
76	  const loyaltyDiscount = loyaltyDiscountFor(basePremium, customer);
77	
78	  const firstInsuranceSurcharge = basePremium * 0.1;
79	
80	  return Math.ceil(basePremium + itemSurcharges - loyaltyDiscount + firstInsuranceSurcharge + PROCESSING_FEE);
81	}
